const body = items[0].json.body || items[0].json;

const notification = {
  type: body.type || 'general',
  phone: body.phone || '',
  customer_name: body.customer_name || 'Customer',
  service: body.service || '',
  amount: body.amount || 0,
  receipt: body.receipt || body.mpesa_receipt || '',
  tracking_id: body.tracking_id || body.id || '',
  message: body.message || '',
  status: body.status || 'completed',
  lang: body.lang || 'en',
  timestamp: new Date().toISOString()
};

return [{ json: notification }];

const n = items[0].json;
let message = '';

const templates = {
  en: {
    payment_confirmed: `✅ Payment Confirmed!

Hi ${n.customer_name},
Your payment of KES ${n.amount} has been received.
M-Pesa Ref: ${n.receipt}
Service: ${n.service}
Tracking #: ${n.tracking_id}

Thank you for choosing Aego Cyber Cafe!
📍 Nyatike, Migori County`,

    service_ready: `📄 Your Document is Ready!

Hi ${n.customer_name},
Your ${n.service} is ready for collection.
Tracking #: ${n.tracking_id}

Please visit Aego Cyber Cafe to collect it.
📍 Nyatike, Migori County`,

    request_received: `📋 Request Received!

Hi ${n.customer_name},
We've received your ${n.service} request.
Tracking #: ${n.tracking_id}

We'll notify you when it's ready.
Thank you for your patience!`,

    general: n.message || 'Update from Aego Cyber Cafe'
  },
  sw: {
    payment_confirmed: `✅ Malipo Yamethibitishwa!

Habari ${n.customer_name},
Malipo yako ya KES ${n.amount} yamepokelewa.
Marejeo ya M-Pesa: ${n.receipt}
Huduma: ${n.service}
Nambari ya Ufuatiliaji: ${n.tracking_id}

Asante kwa kuchagua Aego Cyber Cafe!
📍 Nyatike, Kaunti ya Migori`,

    service_ready: `📄 Hati Yako ni Tayari!

Habari ${n.customer_name},
${n.service} yako ni tayari kwa kuchukuliwa.
Nambari ya Ufuatiliaji: ${n.tracking_id}

Tafadhali tembelea Aego Cyber Cafe.
📍 Nyatike, Kaunti ya Migori`,

    request_received: `📋 Ombi Limepokelewa!

Habari ${n.customer_name},
Tumepokea ombi lako la ${n.service}.
Nambari ya Ufuatiliaji: ${n.tracking_id}

Tutakujulisha itakapokuwa tayari.`,

    general: n.message || 'Sasisha kutoka Aego Cyber Cafe'
  },
  lu: {
    payment_confirmed: `✅ Chul Osechulwo!

Maber ${n.customer_name},
Chul mar ng'eno KES ${n.amount} ng'eyo gi.
M-Pesa Ref: ${n.receipt}
Tich: ${n.service}
Tracking #: ${n.tracking_id}

Awuono ni wach Aego Cyber Cafe!
📍 Nyatike, Migori`,

    service_ready: `📄 Koro Gi Miyo!

Maber ${n.customer_name},
${n.service} mar gi en koro.
Tracking #: ${n.tracking_id}

Ket Aego Cyber Cafe ka in.
📍 Nyatike, Migori`,

    request_received: `📋 Yien Ng'eyo!

Maber ${n.customer_name},
Yien mar ${n.service} ng'eyo.
Tracking #: ${n.tracking_id}

Wa biro nyis ka koro.`,

    general: n.message || 'Update from Aego Cyber Cafe'
  }
};

const langTemplates = templates[n.lang] || templates.en;
message = langTemplates[n.type] || langTemplates.general || n.message;

return [{ json: { ...n, formatted_message: message, phone: n.phone } }];
